function getPreferredControllerPdpUrl(
  model: string | undefined | null,
  niProductDescription: NiProductDescription | null,
): string | null {
  if (niProductDescription) {
    const explicitUrl = String(niProductDescription.url || '').trim()
    return explicitUrl || null
  }

  return getControllerPdpUrlFromModel(model)
}

function getControllerModelToken(model: string | undefined | null): string | null {
  const raw = (model || '').trim()
  if (!raw) return null
  const match = raw.match(/(PXI[Ee]?-[A-Za-z0-9]+)/)
  return match ? match[1] : null
}

function getControllerPdpUrlFromModel(model: string | undefined | null): string | null {
  const token = getControllerModelToken(model)
  if (!token) return null
  return `https://www.ni.com/en/shop/hardware/pxi-controllers/model-${token.toLowerCase()}`
}

function getControllerNiSpecsFromEmbeddedSpec(spec: EmbeddedControllerSpec | null): PartDatasetSpec[] {
  if (!spec) return []
  const specs: PartDatasetSpec[] = []
  if (spec.processor) specs.push({ key: 'processor_core_df', value: spec.processor })
  if (spec.frequency) specs.push({ key: 'controller_frequency_df', value: spec.frequency })
  if (Number.isFinite(spec.numberOfCores)) specs.push({ key: 'number_of_cores_df', value: String(spec.numberOfCores) })
  return specs
}

function getModuleNiSpecsFromDataAcquisitionSpec(spec: DataAcquisitionModuleSpec | null): PartDatasetSpec[] {
  if (!spec) return []
  const specs: PartDatasetSpec[] = []
  if (spec.analogInputChannels) specs.push({ key: 'analog_input_channels_df', value: spec.analogInputChannels })
  if (spec.inputSamplingRate) specs.push({ key: 'input_sampling_rate_df', value: spec.inputSamplingRate })
  if (spec.analogInputResolution) specs.push({ key: 'analog_input_resolution_df', value: spec.analogInputResolution })
  if (spec.niKeyAttributes) {
    Object.entries(spec.niKeyAttributes).forEach(([key, value]) => {
      if (!value) return
      specs.push({ key, value })
    })
  }
  return specs
}

function getModuleModelToken(model: string | undefined | null): string | null {
  const raw = (model || '').trim()
  if (!raw) return null
  const match = raw.match(/\b((?:PXI[Ee]?|RMX)-[A-Za-z0-9]+)\b/)
  return match ? match[1] : null
}

function normalizeNiPdpUrl(url: string | undefined | null): string | null {
  const value = String(url || '').trim()
  if (!value) return null
  return value.replace('/en-us/', '/en/')
}

function getPreferredModulePdpUrl(
  model: string | undefined | null,
  niProductDescription: NiProductDescription | null,
): string | null {
  const fallbackUrl = 'https://www.ni.com'
  const explicitUrl = normalizeNiPdpUrl(niProductDescription?.url)
  if (explicitUrl && (/\/model-[a-z0-9-]+$/i.test(explicitUrl) || /\/shop\/model\//i.test(explicitUrl))) {
    return explicitUrl
  }

  const token = getModuleModelToken(niProductDescription?.model || model)
  if (!token) return fallbackUrl

  // Legacy PXI DAQ modules do not have NI model pages; avoid emitting broken links.
  if (token.toUpperCase().startsWith('PXI-')) return fallbackUrl

  return `https://www.ni.com/en/shop/model/${token.toLowerCase()}.html`
}

function getDataAcquisitionModuleSpecByModel(model: string | undefined | null): DataAcquisitionModuleSpec | null {
  if (!model) return null
  const direct = dataAcquisitionModuleSpecByModel[model]
  if (direct) return direct

  const normalizedTarget = normalizeModelKey(model)
  const match = Object.entries(dataAcquisitionModuleSpecByModel).find(([name]) => normalizeModelKey(name) === normalizedTarget)
  return match ? match[1] : null
}

function getAnalogInputChannelsValue(part: PartNumber | null | undefined): string {
  return getDataAcquisitionModuleSpecByModel(part?.model)?.analogInputChannels || '—'
}

function getInputSamplingRateValue(part: PartNumber | null | undefined): string {
  return getDataAcquisitionModuleSpecByModel(part?.model)?.inputSamplingRate || '—'
}

function getAnalogInputResolutionValue(part: PartNumber | null | undefined): string {
  return getDataAcquisitionModuleSpecByModel(part?.model)?.analogInputResolution || '—'
}

function resolvePartImage(part: PartNumber | null | undefined): string {
  if (!part) return NO_IMAGE_AVAILABLE_SRC
  const fromPart = (part as any).productImage
  if (fromPart && String(fromPart).trim()) return String(fromPart)
  const pn = part.partNumber || (part as any).id
  return getNiProductImage(pn) || NO_IMAGE_AVAILABLE_SRC
}

const REQUEST_QUOTE_TOTAL_LABEL = 'Request quote for pricing'

function formatNumericPrice(value: number | null | undefined): string {
  if (value == null || !Number.isFinite(value)) return '—'
  return money(value)
}

function formatPartPrice(part: PartNumber | null | undefined): string {
  if (!part) return money(0)
  if ((part as any).priceLabel) return String((part as any).priceLabel)
  if (Number.isFinite(part.price)) return money(part.price)
  return money(0)
}

function normalizeLifecycleValue(value: string | undefined | null): 'Active' | 'LTB' | 'Mature' | 'Obsolete' {
  const normalized = String(value || '').trim().toLowerCase()
  if (normalized === 'ltb') return 'LTB'
  if (normalized === 'mature') return 'Mature'
  if (normalized === 'obsolete') return 'Obsolete'
  return 'Active'
}

function formatAggregatePrice(total: number, hasQuoteItems: boolean): string {
  return hasQuoteItems ? REQUEST_QUOTE_TOTAL_LABEL : money(total)
}

function parsePriceNumber(value: unknown): number | null {
  if (typeof value === 'number') return Number.isFinite(value) && value > 0 ? value : null
  if (typeof value !== 'string') return null
  if (/call\s*for\s*price/i.test(value)) return null
  const match = value.replace(/,/g, '').match(/\$?\s*([0-9]+(?:\.[0-9]+)?)/)
  if (!match) return null
  const parsed = Number(match[1])
  return Number.isFinite(parsed) && parsed > 0 ? parsed : null
}

function getModulePlaceholderPricing(
  model: string | null | undefined,
  curatedModuleSpec: OscilloscopeModuleSpec | null,
): { price: number | null; priceLabel?: string } {
  const numericCandidates: number[] = []
  const labelCandidates: string[] = []

  const pushCandidates = (specs: Record<string, string> | undefined) => {
    if (!specs) return
    Object.entries(specs).forEach(([key, rawValue]) => {
      if (!/price/i.test(key)) return
      const parsed = parsePriceNumber(rawValue)
      if (parsed != null) {
        numericCandidates.push(parsed)
      } else if (typeof rawValue === 'string' && /call\s*for\s*price/i.test(rawValue)) {
        labelCandidates.push('Call for Price')
      }
    })
  }

  pushCandidates(curatedModuleSpec?.niProductSpecs)

  const daqSpec = getDataAcquisitionModuleSpecByModel(model || curatedModuleSpec?.model)
  pushCandidates(daqSpec?.niKeyAttributes)

  if (numericCandidates.length > 0) {
    return { price: Math.max(...numericCandidates) }
  }
  if (labelCandidates.length > 0) {
    return { price: null, priceLabel: 'Call for Price' }
  }

  const normalizedModel = normalizeModelForLookup(model || curatedModuleSpec?.model)
  const modelPriceOverride = moduleModelPriceOverrideByNormalizedModel[normalizedModel]
  if (modelPriceOverride) {
    const overridePrice = parsePriceNumber(modelPriceOverride.priceUsd)
    if (overridePrice != null) {
      return { price: overridePrice }
    }
    if (typeof modelPriceOverride.priceLabel === 'string' && /call\s*for\s*price/i.test(modelPriceOverride.priceLabel)) {
      return { price: null, priceLabel: 'Call for Price' }
    }
  }

  return { price: null }
}

function makeWhitelistedPlaceholderPart(
  partNumber: string,
  category: 'controller' | 'module',
  groupName: string,
): PartNumber {
  const groupLabel = formatWhitelistGroupName(groupName)
  const csvModel = (pnToModel as Record<string, string>)[partNumber?.trim()]
  const controllerSpec = category === 'controller' ? getEmbeddedControllerSpec(partNumber) : null
  const curatedModuleSpec = category === 'module' ? getCuratedModuleSpec(partNumber) : null
  const modulePricing = category === 'module'
    ? getModulePlaceholderPricing(csvModel || curatedModuleSpec?.model, curatedModuleSpec)
    : { price: null as number | null }
  const niProductDescription = getNiProductDescription(partNumber)
  const niProductImage = getNiProductImage(partNumber)

  return {
    partNumber,
    description: curatedModuleSpec?.description || niProductDescription?.shortDescription || `Whitelisted ${groupLabel} dataset item.`,
    price: typeof controllerSpec?.priceUsd === 'number'
      ? controllerSpec.priceUsd
      : (modulePricing.price ?? 0),
    lifecycle: normalizeLifecycleValue(curatedModuleSpec?.lifecycle),
    rohs: true,
    reach: 'Compliant',
    primarySite: 'Unknown',
    model: csvModel || curatedModuleSpec?.model || (category === 'controller'
      ? 'Controller model unavailable'
      : `${groupLabel} module (model unavailable)`),
    category,
    family: groupLabel,
    ...(controllerSpec?.processor ? { processor: controllerSpec.processor } : {}),
    ...(controllerSpec?.frequency ? { frequency: controllerSpec.frequency } : {}),
    ...(Number.isFinite(controllerSpec?.numberOfCores) ? { numberOfCores: controllerSpec?.numberOfCores } : {}),
    ...(controllerSpec?.priceLabel ? { priceLabel: controllerSpec.priceLabel } : {}),
    ...(modulePricing.priceLabel ? { priceLabel: modulePricing.priceLabel } : {}),
    ...(modulePricing.price != null
      ? {
          niStartingPriceUsd: modulePricing.price,
          niListPriceUsd: modulePricing.price,
          niPriceCurrency: 'USD',
        }
      : {}),
    ...(curatedModuleSpec?.niProductSpecs ? { niProductSpecs: curatedModuleSpec.niProductSpecs } : {}),
    ...(niProductDescription?.longDescription ? { longDescription: niProductDescription.longDescription } : {}),
    productImage: niProductImage || NO_IMAGE_AVAILABLE_SRC,
  }
}

function getHealth(config: Configuration | null, catalog: Catalog | null, whitelist: AllowedPnRuntime | null, rules: BusinessRules | null) {
  if (!config || !catalog) {
    return {
      validation: null as ValidationResult | null,
      total: 0,
      totalDisplay: money(0),
      hasQuoteItems: false,
      lineItems: [] as PricingLineItem[],
      warnings: [] as string[],
    }
  }
  const pricing = calculatePriceBreakdown(config, catalog)
  const validation = validateConfiguration(config, {
    catalog,
    whitelist,
    businessRules: rules,
    hasPrice: Number.isFinite(pricing.total),
  })
  return {
    validation,
    total: pricing.total,
    totalDisplay: formatAggregatePrice(pricing.total, pricing.hasQuoteItems),
    hasQuoteItems: pricing.hasQuoteItems,
    lineItems: pricing.lineItems,
    warnings: pricing.warnings,
  }
}


function money(value: number): string {
  return `$${value.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
}

function formatPxiConfigurationId(id: string): string {
  const normalized = normalize(id)
  if (!normalized.startsWith('PXI-')) {
    return id
  }

  const digits = normalized.replace(/[^0-9]/g, '')
  const padded = (digits.slice(-8) || '0').padStart(8, '0')
  return `PXI-${padded}`
}

function getPlatformLabel(id: string): 'PXI' | 'cRIO' | 'cDAQ' {
  const normalized = normalize(id)
  if (normalized.startsWith('CRIO-')) return 'cRIO'
  if (normalized.startsWith('CDAQ-')) return 'cDAQ'
  return 'PXI'
}

