function getConfigurationPartCount(config: Configuration): number {
  const chassisCount = config.chassis ? 1 + (config.chassis.accessories?.length || 0) : 0
  const controllerCount = config.controller ? 1 + (config.controller.accessories?.length || 0) : 0
  const moduleCount = (config.modules || []).length
  const moduleAccessoryCount = (config.modules || []).reduce((sum, module) => sum + (module.accessories?.length || 0), 0)
  const systemAccessoryCount = (config.systemAccessories || []).length
  const serviceCount = (config.services || []).length

  return chassisCount + controllerCount + moduleCount + moduleAccessoryCount + systemAccessoryCount + serviceCount
}

