  const moduleSearchResults = useMemo(() => {
    const query = moduleAddByPartNumberOrModelQuery.trim().toLowerCase()
    if (!query || query.length < 3) return [] as PartNumber[]

    const score = (part: PartNumber): number => {
      const model = String(part.model || '').toLowerCase()
      const partNumber = String(part.partNumber || '').toLowerCase()

      if (partNumber === query) return 0
      if (model === query) return 1
      if (partNumber.startsWith(query)) return 2
      if (model.startsWith(query)) return 3

      const pnContainsAt = partNumber.indexOf(query)
      if (pnContainsAt >= 0) return 10 + pnContainsAt

      const modelContainsAt = model.indexOf(query)
      if (modelContainsAt >= 0) return 20 + modelContainsAt

      return Number.MAX_SAFE_INTEGER
    }

    return [...moduleSearchCandidates]
      .map((part) => ({ part, score: score(part) }))
      .filter((entry) => entry.score < Number.MAX_SAFE_INTEGER)
      .sort((left, right) => {
        if (left.score !== right.score) return left.score - right.score
        const pnCompare = String(left.part.partNumber || '').localeCompare(String(right.part.partNumber || ''), undefined, { numeric: true, sensitivity: 'base' })
        if (pnCompare !== 0) return pnCompare
        return String(left.part.model || '').localeCompare(String(right.part.model || ''), undefined, { numeric: true, sensitivity: 'base' })
      })
      .map((entry) => entry.part)
  }, [moduleAddByPartNumberOrModelQuery, moduleSearchCandidates])

