  const partDatasetSections = useMemo(() => {
    if (!catalog) return [] as PartDatasetSection[]

    const allowedPns = new Set((whitelist?.allowedPns || []).map((pn) => normalize(pn)))
    const whitelistGroupsByPn = new Map<string, string[]>()
    Object.entries(whitelist?.allowedByGroup || {}).forEach(([groupName, partNumbers]) => {
      ;(partNumbers || []).forEach((pn) => {
        const normalized = normalize(pn)
        if (!normalized) return
        const groups = whitelistGroupsByPn.get(normalized) || []
        if (!groups.includes(groupName)) groups.push(groupName)
        whitelistGroupsByPn.set(normalized, groups)
      })
    })

    const configurationReferences = collectConfigurationPartReferences(configurations)
    const businessRuleReferences = collectBusinessRulePartReferences(businessRules)

    const allCatalogParts = [
      ...flatten(catalog.chassis),
      ...flatten(catalog.controllers),
      ...flatten(catalog.modules),
    ]

    const rowsByPn = new Map<string, PartDatasetRow>()
    allCatalogParts.forEach((part) => {
      const normalizedPn = normalize(part.partNumber)
      if (!normalizedPn) return

      const whitelistGroups = whitelistGroupsByPn.get(normalizedPn) || []
      const whitelistGroupLabel = whitelistGroups.length > 0
        ? whitelistGroups.map((group) => MODULE_WHITELIST_GROUP_LABELS[group] || CONTROLLER_WHITELIST_GROUP_LABELS[group] || formatWhitelistGroupName(group)).join(', ')
        : '—'
      const category = resolveDatasetCategory(part, whitelistGroups)
      const subgroup = resolveDatasetSubgroup(category, part, whitelistGroups)
      const niProductDescription = getNiProductDescription(part.partNumber)
      const controllerSpec = category === 'controller' ? getEmbeddedControllerSpec(part.partNumber) : null
      const controllerNiSpecs = category === 'controller' ? getControllerNiSpecsFromEmbeddedSpec(controllerSpec) : []
      const controllerPdpUrl = category === 'controller'
        ? getPreferredControllerPdpUrl(part.model, niProductDescription)
        : null
      const moduleSpec = category === 'module' ? getDataAcquisitionModuleSpecByModel(part.model) : null
      const moduleNiSpecs = category === 'module' ? getModuleNiSpecsFromDataAcquisitionSpec(moduleSpec) : []
      const modulePdpUrl = category === 'module'
        ? getPreferredModulePdpUrl(part.model, niProductDescription)
        : null
      const datasetSources: PartDatasetSource[] = [
        { source: 'catalog.json', detail: `${part.category} / ${part.family || 'Uncategorized family'}` },
      ]

      if (allowedPns.has(normalizedPn)) {
        datasetSources.push({ source: 'allowed-pns-runtime.json', detail: whitelistGroupLabel === '—' ? 'Allowed part number' : whitelistGroupLabel })
      }

      const businessRefs = Array.from(businessRuleReferences.get(normalizedPn) || [])
      if (businessRefs.length > 0) {
        datasetSources.push({ source: 'businessRules.json', detail: businessRefs.join(', ') })
      }

      const configRefs = Array.from(configurationReferences.get(normalizedPn) || [])
      if (configRefs.length > 0) {
        datasetSources.push({ source: 'configurations.json', detail: `Used in ${configRefs.length} config(s): ${configRefs.join(', ')}` })
      }

      rowsByPn.set(normalizedPn, {
        key: normalizedPn,
        category,
        subgroup,
        partNumber: part.partNumber,
        categoryLabel: category === 'other' ? 'Other' : category.charAt(0).toUpperCase() + category.slice(1),
        model: part.model || 'Unknown',
        productImage: (part as any).productImage || NO_IMAGE_AVAILABLE_SRC,
        family: part.family || '—',
        description: part.description || '—',
        longDescription: (part as any).longDescription || '—',
        integrated: category === 'chassis' ? (part.integrated ? 'Yes' : 'No') : '—',
        lifecycle: part.lifecycle || '—',
        primarySite: part.primarySite || '—',
        whitelistGroup: whitelistGroupLabel,
        hostInterface: (category === 'chassis' || category === 'controller') ? extractHostInterface(part) : '—',
        processor: category === 'controller' ? ((part as any).processor || '—') : '—',
        frequency: category === 'controller' ? ((part as any).frequency || '—') : '—',
        numberOfCores: category === 'controller'
          ? (Number.isFinite((part as any).numberOfCores) ? String((part as any).numberOfCores) : '—')
          : '—',
        analogInputChannels: category === 'module' ? getAnalogInputChannelsValue(part) : '—',
        inputSamplingRate: category === 'module' ? getInputSamplingRateValue(part) : '—',
        analogInputResolution: category === 'module' ? getAnalogInputResolutionValue(part) : '—',
        systemBandwidth: category === 'chassis' ? getSystemBandwidthValue(part) : '—',
        peripheralSlots: category === 'chassis' ? getPeripheralSlotsValue(part) : '—',
        price: Number.isFinite(part.price) ? part.price : null,
        priceLabel: typeof (part as any).priceLabel === 'string' ? (part as any).priceLabel : undefined,
        niModelName: (category === 'chassis' || category === 'controller' || category === 'module')
          ? ((part as any).niModelName
            || (category === 'controller' ? (niProductDescription?.model || getControllerModelToken(part.model) || part.model) : part.model)
            || '—')
          : '—',
        niModelShortDescription: (category === 'chassis' || category === 'controller' || category === 'module')
          ? ((part as any).niModelShortDescription || niProductDescription?.shortDescription || part.description || '—')
          : '—',
        niStartingPriceUsd: (category === 'chassis' || category === 'controller' || category === 'module')
          ? (() => {
            const startingPrice = Number((part as any).niStartingPriceUsd)
            const fallbackStartingPrice = category === 'controller' ? Number(controllerSpec?.priceUsd) : Number.NaN
            const moduleFallbackStartingPrice = category === 'module' ? Number(part.price) : Number.NaN
            const value = Number.isFinite(startingPrice)
              ? startingPrice
              : (Number.isFinite(fallbackStartingPrice) ? fallbackStartingPrice : moduleFallbackStartingPrice)
            return Number.isFinite(value)
              ? `$${value.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
              : '—'
          })()
          : '—',
        niPriceCurrency: (category === 'chassis' || category === 'controller' || category === 'module')
          ? ((part as any).niPriceCurrency || (Number.isFinite(controllerSpec?.priceUsd) || Number.isFinite(part.price) ? 'USD' : '—'))
          : '—',
        niListPriceUsd: (category === 'chassis' || category === 'controller' || category === 'module')
          ? (() => {
            const listPrice = Number((part as any).niListPriceUsd)
            const fallbackListPrice = category === 'controller' ? Number(controllerSpec?.priceUsd) : Number.NaN
            const moduleFallbackListPrice = category === 'module' ? Number(part.price) : Number.NaN
            const value = Number.isFinite(listPrice)
              ? listPrice
              : (Number.isFinite(fallbackListPrice) ? fallbackListPrice : moduleFallbackListPrice)
            return Number.isFinite(value)
              ? `$${value.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
              : '—'
          })()
          : '—',
        niProductSpecs: (category === 'chassis' || category === 'controller' || category === 'module')
          ? (() => {
            const fromPart = Object.entries(((part as any).niProductSpecs || {}) as Record<string, unknown>)
              .map(([key, value]) => ({ key, value: typeof value === 'string' ? value : String(value ?? '—') }))
            if (fromPart.length > 0) return fromPart
            if (category === 'module') {
              const fromCurated = Object.entries(getCuratedModuleSpec(part.partNumber)?.niProductSpecs || {})
                .map(([key, value]) => ({ key, value: typeof value === 'string' ? value : String(value ?? '—') }))
              if (fromCurated.length > 0) return fromCurated
            }
            if (category === 'controller') return controllerNiSpecs
            if (category === 'module') return moduleNiSpecs
            return []
          })()
          : [],
        needsManualReview: (part as any).needsManualReview ? 'Yes' : 'No',
        manualReviewSummary: Array.isArray((part as any).manualReviewDiffs)
          ? ((part as any).manualReviewDiffs as Array<{ field?: string; niValue?: string }>).map((diff) => {
            const field = diff?.field || 'field'
            const niValue = diff?.niValue ? `: ${String(diff.niValue)}` : ''
            return `${field}${niValue}`
          }).join(' | ') || '—'
          : '—',
        niPdpUrl: typeof (part as any).niPdpUrl === 'string' && (part as any).niPdpUrl.trim().length > 0
          ? (part as any).niPdpUrl
          : (niProductDescription?.url || controllerPdpUrl || modulePdpUrl || '—'),
        datasetSources,
      })
    })

    const referencedOnlyPns = new Set<string>()
    allowedPns.forEach((pn) => referencedOnlyPns.add(pn))
    Array.from(configurationReferences.keys()).forEach((pn) => referencedOnlyPns.add(pn))
    Array.from(businessRuleReferences.keys()).forEach((pn) => referencedOnlyPns.add(pn))

    referencedOnlyPns.forEach((pn) => {
      if (rowsByPn.has(pn)) return

      const whitelistGroups = whitelistGroupsByPn.get(pn) || []
      const whitelistGroupLabel = whitelistGroups.length > 0
        ? whitelistGroups.map((group) => MODULE_WHITELIST_GROUP_LABELS[group] || CONTROLLER_WHITELIST_GROUP_LABELS[group] || formatWhitelistGroupName(group)).join(', ')
        : '—'
      const category = resolveDatasetCategory(null, whitelistGroups)
      const subgroup = resolveDatasetSubgroup(category, null, whitelistGroups)
      const controllerSpec = category === 'controller' ? getEmbeddedControllerSpec(pn) : null
      const niProductDescription = getNiProductDescription(pn)
      const niProductImage = getNiProductImage(pn)
      const curatedModuleSpec = category === 'module' ? getCuratedModuleSpec(pn) : null
      const rowModel = (pnToModel as Record<string, string>)[pn.trim()] || 'Unknown'
      const modularChassisSpec = category === 'chassis' ? getChassisSpecByModel(rowModel) : null
      const dataAcquisitionSpec = category === 'module' ? getDataAcquisitionModuleSpecByModel(rowModel) : null
      const controllerNiSpecs = category === 'controller' ? getControllerNiSpecsFromEmbeddedSpec(controllerSpec) : []
      const controllerModelToken = category === 'controller' ? getControllerModelToken(rowModel) : null
      const controllerPdpUrl = category === 'controller'
        ? getPreferredControllerPdpUrl(rowModel, niProductDescription)
        : null
      const moduleNiSpecs = category === 'module' ? getModuleNiSpecsFromDataAcquisitionSpec(dataAcquisitionSpec) : []
      const modulePdpUrl = category === 'module'
        ? getPreferredModulePdpUrl(rowModel, niProductDescription)
        : null
      const datasetSources: PartDatasetSource[] = []

      if (allowedPns.has(pn)) {
        datasetSources.push({ source: 'allowed-pns-runtime.json', detail: whitelistGroupLabel === '—' ? 'Allowed part number' : whitelistGroupLabel })
      }

      const businessRefs = Array.from(businessRuleReferences.get(pn) || [])
      if (businessRefs.length > 0) {
        datasetSources.push({ source: 'businessRules.json', detail: businessRefs.join(', ') })
      }

      const configRefs = Array.from(configurationReferences.get(pn) || [])
      if (configRefs.length > 0) {
        datasetSources.push({ source: 'configurations.json', detail: `Used in ${configRefs.length} config(s): ${configRefs.join(', ')}` })
      }

      rowsByPn.set(pn, {
        key: pn,
        category,
        subgroup,
        partNumber: pn,
        categoryLabel: category === 'other' ? 'Other' : category.charAt(0).toUpperCase() + category.slice(1),
        model: rowModel,
        productImage: niProductImage || NO_IMAGE_AVAILABLE_SRC,
        family: '—',
        description: curatedModuleSpec?.description || niProductDescription?.shortDescription || 'Not present in catalog.json',
        longDescription: niProductDescription?.longDescription || '—',
        integrated: '—',
        lifecycle: curatedModuleSpec?.lifecycle || '—',
        primarySite: '—',
        whitelistGroup: whitelistGroupLabel,
        hostInterface: modularChassisSpec?.hostInterface || '—',
        processor: controllerSpec?.processor || '—',
        frequency: controllerSpec?.frequency || '—',
        numberOfCores: Number.isFinite(controllerSpec?.numberOfCores) ? String(controllerSpec?.numberOfCores) : '—',
        analogInputChannels: dataAcquisitionSpec?.analogInputChannels || '—',
        inputSamplingRate: dataAcquisitionSpec?.inputSamplingRate || '—',
        analogInputResolution: dataAcquisitionSpec?.analogInputResolution || '—',
        systemBandwidth: modularChassisSpec?.systemBandwidth || '—',
        peripheralSlots: Number.isFinite(modularChassisSpec?.peripheralSlots) ? String(modularChassisSpec?.peripheralSlots) : '—',
        price: typeof controllerSpec?.priceUsd === 'number' ? controllerSpec.priceUsd : null,
        priceLabel: controllerSpec?.priceLabel,
        niModelName: category === 'controller'
          ? (niProductDescription?.model || controllerModelToken || rowModel || '—')
          : (category === 'module' ? rowModel : '—'),
        niModelShortDescription: (category === 'controller' || category === 'module') ? (curatedModuleSpec?.description || niProductDescription?.shortDescription || rowModel || '—') : '—',
        niStartingPriceUsd: category === 'controller' && Number.isFinite(controllerSpec?.priceUsd)
          ? `$${Number(controllerSpec?.priceUsd).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
          : '—',
        niPriceCurrency: category === 'controller' && Number.isFinite(controllerSpec?.priceUsd) ? 'USD' : '—',
        niListPriceUsd: category === 'controller' && Number.isFinite(controllerSpec?.priceUsd)
          ? `$${Number(controllerSpec?.priceUsd).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
          : '—',
        niProductSpecs: category === 'controller'
          ? controllerNiSpecs
          : (category === 'module'
            ? (() => {
              const fromCurated = Object.entries(curatedModuleSpec?.niProductSpecs || {})
                .map(([key, value]) => ({ key, value: typeof value === 'string' ? value : String(value ?? '—') }))
              if (fromCurated.length > 0) return fromCurated
              return moduleNiSpecs
            })()
            : []),
        needsManualReview: 'No',
        manualReviewSummary: '—',
        niPdpUrl: category === 'controller'
          ? (niProductDescription?.url || controllerPdpUrl || '—')
          : (category === 'module' ? (modulePdpUrl || '—') : '—'),
        datasetSources,
      })
    })

    const sectionsMap = new Map<string, PartDatasetSection>()
    const categoryLabels: Record<'chassis' | 'controller' | 'module' | 'other', string> = {
      chassis: 'Chassis',
      controller: 'Controllers',
      module: 'Modules',
      other: 'Other',
    }

    rowsByPn.forEach((row) => {
      const sectionKey = `${row.category}::${row.subgroup}`
      if (!sectionsMap.has(sectionKey)) {
        sectionsMap.set(sectionKey, {
          category: row.category,
          categoryLabel: categoryLabels[row.category],
          subgroup: row.subgroup,
          rows: [],
        })
      }
      sectionsMap.get(sectionKey)?.rows.push(row)
    })

    const categoryOrder: Record<'chassis' | 'controller' | 'module' | 'other', number> = {
      chassis: 0,
      controller: 1,
      module: 2,
      other: 3,
    }

    return Array.from(sectionsMap.values())
      .map((section) => ({
        ...section,
        rows: [...section.rows].sort((a, b) => {
          const modelComparison = a.model.localeCompare(b.model)
          if (modelComparison !== 0) return modelComparison
          return a.partNumber.localeCompare(b.partNumber)
        }),
      }))
      .sort((a, b) => {
        const categoryComparison = categoryOrder[a.category] - categoryOrder[b.category]
        if (categoryComparison !== 0) return categoryComparison
        return a.subgroup.localeCompare(b.subgroup)
      })
  }, [businessRules, catalog, configurations, whitelist])

  if (loading) return <div className="flex min-h-screen items-center justify-center text-sm text-slate-500">Loading data…</div>
  if (error) return <div className="p-8 text-sm text-red-700">Error loading data: {error}</div>

  const navigate = (next: Screen) => setScreen(next)

  const startConfiguration = () => {
    const cfg = createConfiguration()
    setDetailDraft({
      name: cfg.name || '',
      description: cfg.description || '',
      deliveryPreference: cfg.deliveryPreference || 'assembled',
    })
    setScreen('start')
  }

  const openConfigurationScreen = (config: Configuration, target: Screen) => {
    selectConfiguration(config.id)
    setDetailDraft({
      name: config.name || '',
      description: config.description || '',
      deliveryPreference: config.deliveryPreference || 'assembled',
    })
    setScreen(target)
  }

  const createModuleInstanceId = (partNumber: string) => {
    const random = Math.random().toString(36).slice(2, 8)
    return `mod-${normalize(partNumber)}-${Date.now()}-${random}`
  }

  const resetModulePlacementDraft = () => {
    setModulePlacementDraft(createModulePlacementDraftState(currentConfiguration?.modules || []))
  }

  const updateModulePlacementFixed = (moduleId: string, fixed: boolean) => {
    setModulePlacementDraft((prev) => ({
      ...prev,
      [moduleId]: {
        position: prev[moduleId]?.position ?? (currentConfiguration?.modules.find((module) => module.id === moduleId)?.position ?? null),
        fixed,
      },
    }))
  }

  const updateModuleFuturePlacement = (moduleId: string, nextPosition: number) => {
    const modules = currentConfiguration?.modules || []
    if (modules.length === 0) return

    setModulePlacementDraft((prev) => {
      const nextDraft = { ...prev }
      for (const module of modules) {
        if (!nextDraft[module.id]) {
          nextDraft[module.id] = {
            position: module.position ?? null,
            fixed: Boolean(module.fixed),
          }
        }
      }

      const targetModule = nextDraft[moduleId]
      if (!targetModule || targetModule.position === nextPosition) return nextDraft

      const displacedEntry = Object.entries(nextDraft).find(([otherId, item]) => otherId !== moduleId && item.position === nextPosition)
      if (!displacedEntry) {
        nextDraft[moduleId] = { ...targetModule, position: nextPosition }
        return nextDraft
      }

      const [displacedModuleId, displacedModule] = displacedEntry
      if (displacedModule.fixed) {
        setActionModal({ open: true, title: 'That slot is locked and cannot be reassigned automatically.' })
        return prev
      }

      const selectedCurrentPosition = targetModule.position
      nextDraft[moduleId] = { ...targetModule, position: nextPosition }
      nextDraft[displacedModuleId] = { ...displacedModule, position: null }

      const availableSlots = (maxModuleSlots
        ? Array.from({ length: maxModuleSlots }, (_, index) => index + 1)
        : moduleSlotOptions)

      const firstFreeSlot = availableSlots.find((slot) => !Object.entries(nextDraft).some(([otherId, item]) => otherId !== displacedModuleId && item.position === slot))

      if (firstFreeSlot === undefined) {
        if (selectedCurrentPosition !== null) {
          nextDraft[displacedModuleId] = { ...displacedModule, position: selectedCurrentPosition }
          return nextDraft
        }

        setActionModal({ open: true, title: 'No free slot is available for the displaced module.' })
        return prev
      }

      nextDraft[displacedModuleId] = { ...displacedModule, position: firstFreeSlot }
      return nextDraft
    })
  }

  const applyModulePlacementDraft = () => {
    if (!currentConfiguration) return

    const updatedModules = currentConfiguration.modules
      .map((module) => ({
        ...module,
        position: modulePlacementDraft[module.id]?.position ?? module.position ?? null,
        fixed: modulePlacementDraft[module.id]?.fixed ?? Boolean(module.fixed),
      }))
      .sort((left, right) => {
        const leftPosition = left.position ?? Number.MAX_SAFE_INTEGER
        const rightPosition = right.position ?? Number.MAX_SAFE_INTEGER
        if (leftPosition !== rightPosition) return leftPosition - rightPosition
        return left.id.localeCompare(right.id)
      })

    updateCurrentConfiguration({ modules: updatedModules })
  }

