/**
 * Pricing Engine Service
 *
 * Calculates PXI system pricing from catalog data with line-item breakdown.
 */

import { Catalog, Configuration, PartNumber, PriceBreakdown, PricingLineItem, ServiceDetails } from '../types'

const SERVICE_PROGRAM_PRICES: Record<NonNullable<ServiceDetails['program']>, number> = {
  premium: 2962.54,
  standard: 1692.88,
}

const CALIBRATION_PLAN_PRICES: Record<Exclude<ServiceDetails['calibrationPlan'], 'none'>, number> = {
  'expedited-traceable': 438,
  compliant: 681,
  'iso-accredited': 874.5,
}

function roundCurrency(value: number): number {
  return Math.round((value + Number.EPSILON) * 100) / 100
}

function isQuoteRequiredPart(part: PartNumber | null | undefined): boolean {
  return Boolean(part) && roundCurrency(part?.price || 0) === 0
}

function findPart(catalog: Catalog, partRef: string): PartNumber | null {
  const normalized = (partRef || '').toUpperCase()
  const groups = [...catalog.chassis, ...catalog.controllers, ...catalog.modules]

  for (const group of groups) {
    const found = group.partNumbers.find((pn) => {
      const pnByPartNumber = (pn.partNumber || '').toUpperCase()
      const pnById = (pn.id || '').toUpperCase()
      return pnByPartNumber === normalized || pnById === normalized
    })

    if (found) return found
  }

  return null
}

function findAccessoryPrice(catalog: Catalog, category: 'chassis' | 'controllers' | 'modules', partNumber: string): PartNumber | null {
  const items = catalog.accessories?.[category] || []
  const normalized = (partNumber || '').toUpperCase()
  const found = items.find((item: any) => (item.partNumber || '').toUpperCase() === normalized)
  return found || null
}

export function calculatePrice(config: Configuration, catalog: Catalog): number {
  return calculatePriceBreakdown(config, catalog).total
}

export function calculatePriceBreakdown(
  config: Configuration,
  catalog: Catalog,
): PriceBreakdown {
  const components: Record<string, { qty: number; unitPrice: number; total: number }> = {}
  const accessories: Record<string, number> = {}
  const adjustments: Record<string, number> = {}
  const lineItems: PricingLineItem[] = []
  const warnings: string[] = []
  let hasQuoteItems = false

  let subtotal = 0

  // Chassis component
  if (config.chassis) {
    const chassisPart = findPart(catalog, config.chassis.id)
    const unitPrice = roundCurrency(chassisPart?.price || 0)
    const quoteRequired = isQuoteRequiredPart(chassisPart)

    if (!chassisPart) {
      warnings.push(`Missing catalog entry for chassis ${config.chassis.id}`)
    }

    if (quoteRequired) {
      hasQuoteItems = true
    }

    components.Chassis = { qty: 1, unitPrice, total: unitPrice }
    subtotal += unitPrice

    const chassisChildren: PricingLineItem[] = []

    // Chassis accessories
    for (const accId of config.chassis.accessories || []) {
      const acc = findAccessoryPrice(catalog, 'chassis', accId)
      const accessoryPrice = roundCurrency(acc?.price || 0)
      accessories[`Chassis:${accId}`] = accessoryPrice

      if (!acc) {
        warnings.push(`Missing price for chassis accessory ${accId}`)
      }

      chassisChildren.push({
        key: `chassis-accessory-${accId}`,
        type: 'accessory',
        model: acc?.model || accId,
        partNumber: accId,
        description: acc?.description || 'Accessory price unavailable',
        qty: 1,
        unitPrice: accessoryPrice,
        total: accessoryPrice,
        warning: acc ? undefined : 'Price unavailable; set to 0',
      })
    }

    // Chassis power cord adjustment
    if (config.chassis.powerCord) {
      const powerCordOption = catalog.powerCordOptions?.find(
        (option) => option.partNumber === config.chassis?.powerCord,
      )
      const delta = roundCurrency(powerCordOption?.priceAdjustment || 0)
      adjustments[`Power Cord:${config.chassis.powerCord}`] = delta

      chassisChildren.push({
        key: `power-cord-${config.chassis.powerCord}`,
        type: 'adjustment',
        model: powerCordOption?.model || config.chassis.powerCord,
        partNumber: config.chassis.powerCord,
        description: powerCordOption?.description || 'Power cord adjustment',
        qty: 1,
        unitPrice: delta,
        total: delta,
      })
    }

    // Chassis rack kit add-on
    if (config.chassis.rackMountKit) {
      const rackKitOption = catalog.rackMountKitOptions?.find(
        (option) => option.partNumber === config.chassis?.rackMountKit,
      )
      const rackPrice = roundCurrency(rackKitOption?.price || 0)
      adjustments[`Rack Kit:${config.chassis.rackMountKit}`] = rackPrice

      chassisChildren.push({
        key: `rack-kit-${config.chassis.rackMountKit}`,
        type: 'adjustment',
        model: rackKitOption?.model || config.chassis.rackMountKit,
        partNumber: config.chassis.rackMountKit,
        description: rackKitOption?.description || 'Rack mount kit',
        qty: 1,
        unitPrice: rackPrice,
        total: rackPrice,
      })
    }

    lineItems.push({
      key: `chassis-${config.chassis.id}`,
      type: 'chassis',
      model: chassisPart?.model || config.chassis.id,
      partNumber: chassisPart?.partNumber || config.chassis.id,
      description: chassisPart?.description || 'Chassis',
      qty: 1,
      unitPrice,
      total: unitPrice,
      children: chassisChildren,
      warning: chassisPart ? undefined : 'Price unavailable; set to 0',
      quoteRequired,
    })
  }

  // Controller component
  if (config.controller) {
    const controllerPart = findPart(catalog, config.controller.id)
    const unitPrice = roundCurrency(controllerPart?.price || 0)
    const quoteRequired = isQuoteRequiredPart(controllerPart)

    if (!controllerPart) {
      warnings.push(`Missing catalog entry for controller ${config.controller.id}`)
    }

    if (quoteRequired) {
      hasQuoteItems = true
    }

    components.Controller = { qty: 1, unitPrice, total: unitPrice }
    subtotal += unitPrice

    const controllerChildren: PricingLineItem[] = []

    for (const accId of config.controller.accessories || []) {
      const acc = findAccessoryPrice(catalog, 'controllers', accId)
      const accessoryPrice = roundCurrency(acc?.price || 0)
      accessories[`Controller:${accId}`] = accessoryPrice

      if (!acc) {
        warnings.push(`Missing price for controller accessory ${accId}`)
      }

      controllerChildren.push({
        key: `controller-accessory-${accId}`,
        type: 'accessory',
        model: acc?.model || accId,
        partNumber: accId,
        description: acc?.description || 'Accessory price unavailable',
        qty: 1,
        unitPrice: accessoryPrice,
        total: accessoryPrice,
        warning: acc ? undefined : 'Price unavailable; set to 0',
      })
    }

    if (config.controller.powerCord) {
      const powerCordOption = catalog.powerCordOptions?.find(
        (option) => option.partNumber === config.controller?.powerCord,
      )
      const delta = roundCurrency(powerCordOption?.priceAdjustment || 0)
      adjustments[`Power Cord:${config.controller.powerCord}`] = delta

      controllerChildren.push({
        key: `controller-power-cord-${config.controller.powerCord}`,
        type: 'adjustment',
        model: powerCordOption?.model || config.controller.powerCord,
        partNumber: config.controller.powerCord,
        description: powerCordOption?.description || 'Power cord adjustment',
        qty: 1,
        unitPrice: delta,
        total: delta,
      })
    }

    lineItems.push({
      key: `controller-${config.controller.id}`,
      type: 'controller',
      model: controllerPart?.model || config.controller.id,
      partNumber: controllerPart?.partNumber || config.controller.id,
      description: controllerPart?.description || 'Controller',
      qty: 1,
      unitPrice,
      total: unitPrice,
      children: controllerChildren,
      warning: controllerPart ? undefined : 'Price unavailable; set to 0',
      quoteRequired,
    })
  }

  // Module components + accessories
  for (const module of config.modules) {
    const moduleRef = module.id || module.partNumber || ''
    const modulePart = findPart(catalog, moduleRef)
    const unitPrice = roundCurrency(modulePart?.price || 0)
    const quoteRequired = isQuoteRequiredPart(modulePart)

    if (!modulePart) {
      warnings.push(`Missing catalog entry for module ${moduleRef || 'UNKNOWN'}`)
    }

    if (quoteRequired) {
      hasQuoteItems = true
    }

    const key = modulePart?.partNumber || module.id
    const existing = components[key]
    if (existing) {
      existing.qty += 1
      existing.total = roundCurrency(existing.qty * existing.unitPrice)
    } else {
      components[key] = { qty: 1, unitPrice, total: unitPrice }
    }
    subtotal += unitPrice

    const moduleChildren: PricingLineItem[] = []
    for (const accId of module.accessories || []) {
      const acc = findAccessoryPrice(catalog, 'modules', accId)
      const accessoryPrice = roundCurrency(acc?.price || 0)
      accessories[`Module:${accId}`] = accessoryPrice
      if (!acc) {
        warnings.push(`Missing price for module accessory ${accId}`)
      }

      moduleChildren.push({
        key: `module-accessory-${module.id}-${accId}`,
        type: 'accessory',
        model: acc?.model || accId,
        partNumber: accId,
        description: acc?.description || 'Accessory price unavailable',
        qty: 1,
        unitPrice: accessoryPrice,
        total: accessoryPrice,
        warning: acc ? undefined : 'Price unavailable; set to 0',
      })
    }

    lineItems.push({
      key: `module-${module.id}-${module.position ?? 'unassigned'}`,
      type: 'module',
      model: modulePart?.model || module.id,
      partNumber: modulePart?.partNumber || module.id,
      description: modulePart?.description || 'Module',
      qty: 1,
      unitPrice,
      total: unitPrice,
      children: moduleChildren,
      warning: modulePart ? undefined : 'Price unavailable; set to 0',
      quoteRequired,
    })
  }

  const systemAccessoryCatalog: Record<string, { model: string; description: string; price: number }> = {
    'SYS-ACC-KB-001': {
      model: 'Keyboard Bundle',
      description: 'USB keyboard and mouse bundle for system setup and control.',
      price: 149,
    },
    'SYS-ACC-MON-001': {
      model: 'Monitor Bundle',
      description: '24 in monitor bundle for local system visualization and operation.',
      price: 329,
    },
  }

  for (const accessoryId of config.systemAccessories || []) {
    const accessory = systemAccessoryCatalog[(accessoryId || '').toUpperCase()]
    const unitPrice = roundCurrency(accessory?.price || 0)

    if (!accessory) {
      warnings.push(`Missing price for system accessory ${accessoryId}`)
    }

    lineItems.push({
      key: `system-accessory-${accessoryId}`,
      type: 'system-accessory',
      model: accessory?.model || accessoryId,
      partNumber: accessoryId,
      description: accessory?.description || 'System accessory price unavailable',
      qty: 1,
      unitPrice,
      total: unitPrice,
      warning: accessory ? undefined : 'Price unavailable; set to 0',
    })

    accessories[`System Accessory:${accessoryId}`] = unitPrice
  }

  if (config.serviceDetails?.program) {
    const programPrice = roundCurrency(SERVICE_PROGRAM_PRICES[config.serviceDetails.program])

    lineItems.push({
      key: `service-program-${config.serviceDetails.program}`,
      type: 'service',
      model: config.serviceDetails.program === 'premium' ? 'Premium Services' : 'Standard Services',
      partNumber: config.serviceDetails.program === 'premium' ? 'SRV-PREM-001' : 'SRV-STND-001',
      description: config.serviceDetails.program === 'premium'
        ? 'Improve uptime with faster turnaround for repair and calibration.'
        : 'Lower total cost of ownership and avoid unplanned maintenance expenses.',
      qty: 1,
      unitPrice: programPrice,
      total: programPrice,
    })

    accessories[`Service Program:${config.serviceDetails.program}`] = programPrice
  }

  if (config.serviceDetails?.calibrationPlan && config.serviceDetails.calibrationPlan !== 'none') {
    const calibrationPrice = roundCurrency(CALIBRATION_PLAN_PRICES[config.serviceDetails.calibrationPlan])

    lineItems.push({
      key: `service-calibration-${config.serviceDetails.calibrationPlan}`,
      type: 'service',
      model: 'Calibration Plan',
      partNumber: `CAL-${config.serviceDetails.calibrationPlan.toUpperCase()}`,
      description: config.serviceDetails.calibrationPlan,
      qty: 1,
      unitPrice: calibrationPrice,
      total: calibrationPrice,
    })

    accessories[`Calibration:${config.serviceDetails.calibrationPlan}`] = calibrationPrice
  }

  const accessoriesTotal = Object.values(accessories).reduce((a, b) => a + b, 0)
  const adjustmentsTotal = Object.values(adjustments).reduce((a, b) => a + b, 0)
  const total = roundCurrency(subtotal + accessoriesTotal + adjustmentsTotal)

  return {
    components,
    accessories,
    adjustments,
    subtotal: roundCurrency(subtotal),
    total,
    lineItems,
    warnings,
    hasQuoteItems,
  }
}
