/**
 * Configuration Persistence Hook
 *
 * Manages hybrid save strategy:
 * - Auto-save on configuration changes (debounced)
 * - Manual save trigger
 * - Save status tracking
 */

import { useCallback, useEffect, useRef, useState } from 'react'
import type { Configuration } from '../types'
import { saveConfiguration, SaveResult } from '../services/configurationService'

export interface UseConfigurationPersistenceOptions {
  /** Debounce delay for auto-save in milliseconds */
  autoSaveDelayMs?: number
  /** Whether to enable auto-save */
  enableAutoSave?: boolean
  /** Callback when save completes */
  onSaveComplete?: (result: SaveResult) => void
  /** Callback when save error occurs */
  onSaveError?: (error: string) => void
}

export interface SaveStatus {
  isSaving: boolean
  lastSaveTime?: Date
  lastError?: string
  isDirty: boolean
  saveAttempts: number
}

/**
 * Hook for managing configuration persistence
 */
export function useConfigurationPersistence(
  config: Configuration | null,
  options: UseConfigurationPersistenceOptions = {},
): {
  manualSave: () => Promise<SaveResult>
  saveStatus: SaveStatus
  resetStatus: () => void
} {
  const {
    autoSaveDelayMs = 2000,
    enableAutoSave = true,
    onSaveComplete,
    onSaveError,
  } = options

  const [saveStatus, setSaveStatus] = useState<SaveStatus>({
    isSaving: false,
    isDirty: false,
    saveAttempts: 0,
  })

  const autoSaveTimeoutRef = useRef<NodeJS.Timeout | null>(null)
  const previousConfigRef = useRef<Configuration | null>(null)

  /**
   * Perform save and update status
   */
  const performSave = useCallback(
    async (configToSave: Configuration | null): Promise<SaveResult> => {
      if (!configToSave) {
        return {
          success: false,
          id: '',
          error: 'No configuration selected',
        }
      }

      setSaveStatus((prev) => ({
        ...prev,
        isSaving: true,
        lastError: undefined,
      }))

      try {
        const result = await saveConfiguration(configToSave)

        setSaveStatus((prev) => ({
          ...prev,
          isSaving: false,
          isDirty: !result.success,
          lastSaveTime: result.success ? new Date() : prev.lastSaveTime,
          saveAttempts: (result.retryCount || 0) + 1,
          lastError: result.error,
        }))

        if (result.success) {
          onSaveComplete?.(result)
        } else {
          onSaveError?.(result.error || 'Save failed')
        }

        return result
      } catch (error) {
        const errorMsg = error instanceof Error ? error.message : 'Unknown error'

        setSaveStatus((prev) => ({
          ...prev,
          isSaving: false,
          isDirty: true,
          lastError: errorMsg,
        }))

        onSaveError?.(errorMsg)

        return {
          success: false,
          id: configToSave.id,
          error: errorMsg,
        }
      }
    },
    [onSaveComplete, onSaveError],
  )

  /**
   * Manual save trigger
   */
  const manualSave = useCallback(async (): Promise<SaveResult> => {
    // Clear any pending auto-save
    if (autoSaveTimeoutRef.current) {
      clearTimeout(autoSaveTimeoutRef.current)
      autoSaveTimeoutRef.current = null
    }

    return performSave(config)
  }, [config, performSave])

  /**
   * Reset save status
   */
  const resetStatus = useCallback(() => {
    setSaveStatus({
      isSaving: false,
      isDirty: false,
      saveAttempts: 0,
    })
  }, [])

  /**
   * Auto-save effect (detects changes and debounces)
   */
  useEffect(() => {
    if (!config || !enableAutoSave) return

    // Check if configuration has changed
    const hasChanged =
      !previousConfigRef.current ||
      JSON.stringify(previousConfigRef.current) !== JSON.stringify(config)

    if (hasChanged) {
      previousConfigRef.current = JSON.parse(JSON.stringify(config))

      // Mark as dirty
      setSaveStatus((prev) => ({
        ...prev,
        isDirty: true,
      }))

      // Clear existing timeout
      if (autoSaveTimeoutRef.current) {
        clearTimeout(autoSaveTimeoutRef.current)
      }

      // Set new timeout for auto-save
      autoSaveTimeoutRef.current = setTimeout(() => {
        performSave(config)
      }, autoSaveDelayMs)
    }

    // Cleanup on unmount
    return () => {
      if (autoSaveTimeoutRef.current) {
        clearTimeout(autoSaveTimeoutRef.current)
      }
    }
  }, [config, enableAutoSave, autoSaveDelayMs, performSave])

  return {
    manualSave,
    saveStatus,
    resetStatus,
  }
}
