/**
 * Rules Engine Service
 *
 * Handles validation of PXI configurations against MVP business rules.
 */

import { Catalog, Configuration, PartNumber, RulesContext, ValidationIssue, ValidationResult } from '../types'

export type DrawerCategory = 'chassis' | 'controller' | 'module'

const DRAWER_IGNORED_ISSUE_CODES = new Set([
  'CHASSIS_REQUIRED',
  'CONTROLLER_REQUIRED',
  'MODULE_REQUIRED',
  'PRICE_UNAVAILABLE',
])

function normalize(value: string | undefined | null): string {
  return (value || '').trim().toUpperCase()
}

function getAllowedPnSet(whitelist: RulesContext['whitelist']): Set<string> {
  const fromAllowedList = (whitelist?.allowedPns || []).map(normalize)
  const fromGroups = Object.values(whitelist?.allowedByGroup || {})
    .flatMap((group) => group || [])
    .map(normalize)

  return new Set([...fromAllowedList, ...fromGroups].filter(Boolean))
}

function findPart(catalog: Catalog, partRef: string): PartNumber | null {
  const target = normalize(partRef)
  const groups = [...catalog.chassis, ...catalog.controllers, ...catalog.modules]

  for (const group of groups) {
    const found = group.partNumbers.find((pn) => normalize(pn.partNumber) === target || normalize(pn.id) === target)
    if (found) return found
  }

  return null
}

function getApplicableAccessories(
  catalog: Catalog,
  category: 'chassis' | 'controllers' | 'modules',
  model: string | undefined | null,
) {
  const source = (catalog.accessories?.[category] || []) as Array<{
    partNumber: string
    required?: boolean
    appliesToModels?: string[]
  }>
  const normalizedModel = normalize(model)

  return source.filter((item) => {
    const applies = item.appliesToModels || []
    if (applies.length === 0) return true
    return applies.some((value) => normalize(value) === normalizedModel)
  })
}

function hasModuleBusFamilyMismatch(parts: PartNumber[]): boolean {
  const familyTokens = new Set(
    parts
      .map((pn) => normalize(pn.model).includes('PXIE') ? 'PXIE' : normalize(pn.model).includes('PXI') ? 'PXI' : '')
      .filter(Boolean),
  )
  return familyTokens.size > 1
}

function pushIssue(
  bucket: ValidationIssue[],
  code: string,
  message: string,
  ruleRef: string,
  severity: 'error' | 'warning' = 'error',
) {
  bucket.push({ code, message, ruleRef, severity })
}

function getFamilyToken(model: string | undefined | null): 'PXI' | 'PXIE' | null {
  const normalized = normalize(model)
  if (normalized.includes('PXIE')) return 'PXIE'
  if (normalized.includes('PXI')) return 'PXI'
  return null
}

function pushDisabledOptions(
  bucket: Record<string, string[]>,
  key: 'chassis' | 'controllers' | 'modules',
  pns: string[],
  reason: string,
  reasonBucket: Record<string, string>,
) {
  const current = new Set((bucket[key] || []).map(normalize))
  for (const pn of pns) {
    const normalized = normalize(pn)
    if (!normalized) continue
    current.add(normalized)
    reasonBucket[`${key}:${normalized}`] = reason
  }
  bucket[key] = Array.from(current)
}

export function isConfigurationComplete(result: ValidationResult): boolean {
  return result.isComplete
}

export function validateConfiguration(config: Configuration, context: RulesContext): ValidationResult {
  const { catalog, businessRules, whitelist, hasPrice } = context
  const blockingIssues: ValidationIssue[] = []
  const warnings: ValidationIssue[] = []
  const recommendations: string[] = []
  const disabledOptions: Record<string, string[]> = {}
  const disabledOptionReasons: Record<string, string> = {}
  const allowedSet = getAllowedPnSet(whitelist)
  const allChassisPns = catalog.chassis.flatMap((group) => (group.partNumbers || []).map((part) => part.partNumber))
  const allControllerPns = catalog.controllers.flatMap((group) => (group.partNumbers || []).map((part) => part.partNumber))
  const allModulePns = catalog.modules.flatMap((group) => (group.partNumbers || []).map((part) => part.partNumber))

  if (allowedSet.size > 0) {
    pushDisabledOptions(
      disabledOptions,
      'chassis',
      allChassisPns.filter((pn) => !allowedSet.has(normalize(pn))),
      'Outside approved demo whitelist. [mvp-whitelist-001]',
      disabledOptionReasons,
    )
    pushDisabledOptions(
      disabledOptions,
      'controllers',
      allControllerPns.filter((pn) => !allowedSet.has(normalize(pn))),
      'Outside approved demo whitelist. [mvp-whitelist-002]',
      disabledOptionReasons,
    )
    pushDisabledOptions(
      disabledOptions,
      'modules',
      allModulePns.filter((pn) => !allowedSet.has(normalize(pn))),
      'Outside approved demo whitelist. [mvp-whitelist-003]',
      disabledOptionReasons,
    )
  }

  // Rule: chassis, controller, and at least one module are required for completeness.
  if (!config.chassis) {
    pushIssue(blockingIssues, 'CHASSIS_REQUIRED', 'Select a chassis to continue.', 'mvp-required-001')
  }

  if (!config.controller) {
    pushIssue(blockingIssues, 'CONTROLLER_REQUIRED', 'Select a controller to complete this system.', 'mvp-required-002')
  }

  if (config.modules.length === 0) {
    pushIssue(blockingIssues, 'MODULE_REQUIRED', 'Add at least one module to complete this system.', 'mvp-required-003')
  }

  // Rule: selected PNs must be in whitelist.
  if (config.chassis && !allowedSet.has(normalize(config.chassis.id))) {
    pushIssue(blockingIssues, 'CHASSIS_NOT_ALLOWED', 'This chassis is outside the approved demo whitelist.', 'mvp-whitelist-001')
  }

  if (config.controller && !allowedSet.has(normalize(config.controller.id))) {
    pushIssue(blockingIssues, 'CONTROLLER_NOT_ALLOWED', 'This controller is outside the approved demo whitelist.', 'mvp-whitelist-002')
  }

  for (const module of config.modules) {
    const modulePn = module.partNumber || module.id
    if (!allowedSet.has(normalize(modulePn))) {
      pushIssue(blockingIssues, 'MODULE_NOT_ALLOWED', `Module ${modulePn} is outside the approved demo whitelist.`, 'mvp-whitelist-003')
    }
  }

  const chassisPart = config.chassis ? findPart(catalog, config.chassis.id) : null
  const controllerPart = config.controller ? findPart(catalog, config.controller.id) : null
  const moduleParts = config.modules
    .map((module) => findPart(catalog, module.partNumber || module.id || ''))
    .filter(Boolean) as PartNumber[]

  // Rule: integrated controller/chassis behavior.
  if (chassisPart && controllerPart && (chassisPart.integrated || controllerPart.integrated)) {
    const integratedUnits = businessRules?.integratedUnits || []
    const sameIntegratedPartNumber = normalize(config.chassis?.id) === normalize(config.controller?.id)
    const matchedIntegrated = sameIntegratedPartNumber || integratedUnits.some((pair) => {
      const chassisMatches = normalize(pair.chassis) === normalize(chassisPart.model)
        || normalize(pair.chassis) === normalize(config.chassis?.id)
      const controllerMatches = normalize(pair.controller) === normalize(controllerPart.model)
        || normalize(pair.controller) === normalize(config.controller?.id)
      return chassisMatches && controllerMatches
    })

    if (!matchedIntegrated) {
      pushIssue(
        blockingIssues,
        'INTEGRATED_MISMATCH',
        'This integrated chassis requires its matched integrated controller option.',
        'mvp-integrated-001',
      )
    }

    if (businessRules) {
      const integratedControllers = new Set(
        businessRules.integratedUnits
          .filter((pair) => normalize(pair.chassis) === normalize(chassisPart.model) || normalize(pair.chassis) === normalize(config.chassis?.id))
          .map((pair) => normalize(pair.controller)),
      )

      if (integratedControllers.size === 0 && chassisPart.integrated) {
        integratedControllers.add(normalize(config.chassis?.id))
      }

      if (integratedControllers.size > 0) {
        const disabledControllers = catalog.controllers
          .flatMap((group) => group.partNumbers || [])
          .filter((part) => !integratedControllers.has(normalize(part.model)) && !integratedControllers.has(normalize(part.partNumber)))
          .map((part) => part.partNumber)

        pushDisabledOptions(
          disabledOptions,
          'controllers',
          disabledControllers,
          'Requires integrated chassis/controller pair. [mvp-integrated-001]',
          disabledOptionReasons,
        )
      }
    }
  }

  // Rule: slot capacity.
  if (chassisPart && typeof chassisPart.slots === 'number') {
    const controllerConsumesSlot = controllerPart && !controllerPart.integrated ? 1 : 0
    const availableModuleSlots = Math.max(chassisPart.slots - controllerConsumesSlot, 0)
    if (config.modules.length > availableModuleSlots) {
      pushIssue(
        blockingIssues,
        'SLOT_CAPACITY_EXCEEDED',
        `This configuration uses ${config.modules.length} module slots, but only ${availableModuleSlots} are available.`,
        'mvp-slots-001',
      )
    } else if (availableModuleSlots > 0 && config.modules.length < Math.ceil(availableModuleSlots / 3)) {
      pushIssue(
        warnings,
        'SLOT_UNDERUTILIZED',
        `Only ${config.modules.length} of ${availableModuleSlots} module slots are used. This may be valid but not optimal.`,
        'mvp-slots-002',
        'warning',
      )
    }

    if (config.modules.length >= availableModuleSlots) {
      const selectedModulePns = new Set(config.modules.map((m) => normalize(m.partNumber || m.id)))
      const disabledModules = allModulePns.filter((pn) => !selectedModulePns.has(normalize(pn)))
      pushDisabledOptions(
        disabledOptions,
        'modules',
        disabledModules,
        'No remaining module slots available. [mvp-slots-001]',
        disabledOptionReasons,
      )
    }
  }

  // Rule: cooling/power compatibility.
  if (chassisPart && typeof chassisPart.maxPower === 'number') {
    const totalPower = moduleParts.reduce((sum, part) => sum + Number(part.powerConsumption || 0), 0)
    if (totalPower > chassisPart.maxPower) {
      pushIssue(
        blockingIssues,
        'POWER_EXCEEDED',
        `Estimated module power (${totalPower}W) exceeds chassis capacity (${chassisPart.maxPower}W).`,
        'mvp-power-001',
      )
    } else if (totalPower > chassisPart.maxPower * 0.8) {
      pushIssue(
        warnings,
        'POWER_NEAR_LIMIT',
        `Estimated module power is near chassis capacity (${totalPower}W of ${chassisPart.maxPower}W).`,
        'mvp-power-002',
        'warning',
      )
    }
  }

  // Rule: no mixing incompatible module families.
  if (moduleParts.length > 1 && hasModuleBusFamilyMismatch(moduleParts)) {
    pushIssue(
      blockingIssues,
      'MODULE_FAMILY_MIX',
      'Selected modules mix incompatible PXI/PXIe families for this MVP scope.',
      'mvp-family-001',
    )
  }

  if (moduleParts.length > 0) {
    const selectedFamilies = new Set(moduleParts.map((part) => getFamilyToken(part.model)).filter(Boolean))
    if (selectedFamilies.size === 1) {
      const selectedFamily = Array.from(selectedFamilies)[0]
      const disabledModules = catalog.modules
        .flatMap((group) => group.partNumbers || [])
        .filter((part) => {
          const token = getFamilyToken(part.model)
          return Boolean(token && token !== selectedFamily)
        })
        .map((part) => part.partNumber)

      pushDisabledOptions(
        disabledOptions,
        'modules',
        disabledModules,
        'Incompatible PXI/PXIe module family mix. [mvp-family-001]',
        disabledOptionReasons,
      )
    }
  }

  // Soft rule: required accessories for selected chassis.
  if (config.chassis) {
    const selectedChassisPart = findPart(catalog, config.chassis.id)
    const requiredChassisAccessories = getApplicableAccessories(catalog, 'chassis', selectedChassisPart?.model)
      .filter((item) => item.required)
      .map((item) => item.partNumber)
    const missingRequired = requiredChassisAccessories.filter((partNumber) => !(config.chassis?.accessories || []).includes(partNumber))

    if (missingRequired.length > 0) {
      pushIssue(
        warnings,
        'REQUIRED_ACCESSORY_MISSING',
        `Chassis ${selectedChassisPart?.model || config.chassis.id} is missing required accessory selections: ${missingRequired.join(', ')}.`,
        'mvp-accessory-001',
        'warning',
      )
    }
  }

  // Soft rule: required accessories for selected controller.
  if (config.controller) {
    const selectedControllerPart = findPart(catalog, config.controller.id)
    const requiredControllerAccessories = getApplicableAccessories(catalog, 'controllers', selectedControllerPart?.model)
      .filter((item) => item.required)
      .map((item) => item.partNumber)
    const missingRequired = requiredControllerAccessories.filter((partNumber) => !(config.controller?.accessories || []).includes(partNumber))

    if (missingRequired.length > 0) {
      pushIssue(
        warnings,
        'REQUIRED_ACCESSORY_MISSING',
        `Controller ${selectedControllerPart?.model || config.controller.id} is missing required accessory selections: ${missingRequired.join(', ')}.`,
        'mvp-accessory-002',
        'warning',
      )
    }
  }

  // Soft rule: required accessories for selected modules.
  for (const module of config.modules) {
    const selectedPart = findPart(catalog, module.partNumber || module.id || '')
    const model = normalize(selectedPart?.model)
    const requiredRule = (businessRules?.requiredAccessories || []).find((item) => normalize(item.module) === model)

    const requiredFromCatalog = getApplicableAccessories(catalog, 'modules', selectedPart?.model)
      .filter((item) => item.required)
      .map((item) => item.partNumber)
    const requiredFromRules = (requiredRule?.accessories || [])
      .filter((item) => item.required)
      .map((item) => item.partNumber)

    const required = Array.from(new Set([...requiredFromCatalog, ...requiredFromRules]))
    if (required.length === 0) continue

    const missingRequired = required.filter((partNumber) => !(module.accessories || []).includes(partNumber))
    if (missingRequired.length > 0) {
      pushIssue(
        warnings,
        'REQUIRED_ACCESSORY_MISSING',
        `Module ${selectedPart?.model || module.partNumber || module.id} is missing required accessory selections: ${missingRequired.join(', ')}.`,
        'mvp-accessory-003',
        'warning',
      )
    }
  }

  if (!hasPrice) {
    pushIssue(blockingIssues, 'PRICE_UNAVAILABLE', 'Price could not be calculated for this configuration.', 'mvp-price-001')
  }

  recommendations.push('Use optimization screen warnings to improve performance and serviceability.')

  const isComplete =
    Boolean(config.chassis)
    && Boolean(config.controller)
    && config.modules.length > 0
    && blockingIssues.length === 0
    && hasPrice

  return {
    isValid: blockingIssues.length === 0,
    isComplete,
    blockingIssues,
    warnings,
    recommendations,
    disabledOptions,
    disabledOptionReasons,
  }
}

function getDrawerCandidateConfiguration(
  config: Configuration,
  category: DrawerCategory,
  part: PartNumber,
): Configuration {
  if (category === 'chassis') {
    if (part.integrated) {
      return {
        ...config,
        chassis: {
          id: part.partNumber,
          accessories: [],
        },
        controller: {
          id: part.partNumber,
          accessories: [],
        },
      }
    }

    return {
      ...config,
      chassis: {
        id: part.partNumber,
        accessories: [],
      },
    }
  }

  if (category === 'controller') {
    if (part.integrated) {
      return {
        ...config,
        controller: {
          id: part.partNumber,
          accessories: [],
        },
        chassis: {
          id: part.partNumber,
          accessories: [],
        },
      }
    }

    return {
      ...config,
      controller: {
        id: part.partNumber,
        accessories: [],
      },
    }
  }

  return {
    ...config,
    modules: [
      ...config.modules,
      {
        id: part.partNumber,
        partNumber: part.partNumber,
        position: config.modules.length + 1,
        accessories: [],
        fixed: false,
      },
    ],
  }
}

function getDrawerBlockingReason(result: ValidationResult): string | null {
  const blocking = result.blockingIssues.find((issue) => !DRAWER_IGNORED_ISSUE_CODES.has(issue.code))
  if (!blocking) return null
  return `${blocking.message} [${blocking.ruleRef}]`
}

export function evaluateDrawerOptionAvailability(
  config: Configuration,
  category: DrawerCategory,
  candidates: PartNumber[],
  context: RulesContext,
): Map<string, string> {
  const byPn = new Map<string, string>()

  for (const part of candidates) {
    const pn = part.partNumber
    if (!pn) continue

    if (category === 'chassis' && config.chassis?.id === pn) {
      byPn.set(pn, 'This chassis is already selected.')
      continue
    }

    if (category === 'controller' && config.controller?.id === pn) {
      byPn.set(pn, 'This controller is already selected.')
      continue
    }

    const candidate = getDrawerCandidateConfiguration(config, category, part)
    const validation = validateConfiguration(candidate, {
      ...context,
      hasPrice: true,
    })

    const reason = getDrawerBlockingReason(validation)
    if (reason) {
      byPn.set(pn, reason)
    }
  }

  return byPn
}
