import type { Configuration } from '../types'

const CONFIG_API_BASE = '/api/configurations'
const STORAGE_KEY_PREFIX = 'pxi_config_'

export interface PersistedConfigurationRecord extends Configuration {
  schemaVersion: number
  _metadata?: {
    saveAttempts?: number
    lastSaveError?: string
  }
}

export interface ConfigurationClient {
  save(config: PersistedConfigurationRecord): Promise<{ id: string }>
  load(id: string): Promise<PersistedConfigurationRecord>
  list(): Promise<PersistedConfigurationRecord[]>
  delete(id: string): Promise<void>
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms))
}

export function createMockConfigurationClient(): ConfigurationClient {
  return {
    async save(config) {
      await sleep(100)
      localStorage.setItem(`${STORAGE_KEY_PREFIX}${config.id}`, JSON.stringify(config))
      return { id: config.id }
    },
    async load(id) {
      await sleep(100)
      const stored = localStorage.getItem(`${STORAGE_KEY_PREFIX}${id}`)
      if (!stored) {
        throw new Error(`Configuration ${id} not found`)
      }
      return JSON.parse(stored) as PersistedConfigurationRecord
    },
    async list() {
      await sleep(100)
      const records: PersistedConfigurationRecord[] = []
      for (let i = 0; i < localStorage.length; i += 1) {
        const key = localStorage.key(i)
        if (key?.startsWith(STORAGE_KEY_PREFIX)) {
          const stored = localStorage.getItem(key)
          if (stored) {
            records.push(JSON.parse(stored) as PersistedConfigurationRecord)
          }
        }
      }
      return records
    },
    async delete(id) {
      await sleep(50)
      localStorage.removeItem(`${STORAGE_KEY_PREFIX}${id}`)
    },
  }
}

export function createHttpConfigurationClient(): ConfigurationClient {
  return {
    async save(config) {
      const response = await fetch(`${CONFIG_API_BASE}/${config.id}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(config),
      })

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: ${response.statusText}`)
      }

      return { id: config.id }
    },
    async load(id) {
      const response = await fetch(`${CONFIG_API_BASE}/${id}`)
      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: Configuration not found`)
      }
      return (await response.json()) as PersistedConfigurationRecord
    },
    async list() {
      const response = await fetch(CONFIG_API_BASE)
      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: Failed to list configurations`)
      }
      return (await response.json()) as PersistedConfigurationRecord[]
    },
    async delete(id) {
      const response = await fetch(`${CONFIG_API_BASE}/${id}`, { method: 'DELETE' })
      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: Failed to delete configuration`)
      }
    },
  }
}

function createDefaultClient(): ConfigurationClient {
  return import.meta.env.VITE_USE_MOCK_CONFIGURATION_API === 'false'
    ? createHttpConfigurationClient()
    : createMockConfigurationClient()
}

let activeConfigurationClient: ConfigurationClient = createDefaultClient()

export function getConfigurationClient(): ConfigurationClient {
  return activeConfigurationClient
}

export function setConfigurationClient(client: ConfigurationClient): void {
  activeConfigurationClient = client
}

export function resetConfigurationClient(): void {
  activeConfigurationClient = createDefaultClient()
}