/**
 * Data Loader Service
 *
 * Loads and manages catalog, whitelist, business rules, and configuration data.
 */

import rawCatalog from '../data/catalog.json'
import rawWhitelist from '../data/allowed-pns-runtime.json'
import rawBusinessRules from '../data/businessRules.json'
import pnToModel from '../data/pn-to-model.json'
import embeddedControllerSpecs from '../data/embedded-controller-specs.json'
import niProductDescriptions from '../data/ni-product-descriptions.json'
import niProductImages from '../data/ni-product-images.json'
import { AllowedPnRuntime, BusinessRules, Catalog, CatalogGroup } from '../types'

let catalogCache: Catalog | null = null
let whitelistCache: AllowedPnRuntime | null = null
let businessRulesCache: BusinessRules | null = null

function normalizePn(value: string | undefined | null): string {
  return (value || '').trim().toUpperCase()
}

function getAllowedPnSet(whitelist: AllowedPnRuntime): Set<string> {
  const fromAllowedList = (whitelist.allowedPns || []).map(normalizePn)
  const fromGroups = Object.values(whitelist.allowedByGroup || {})
    .flatMap((group) => group || [])
    .map(normalizePn)

  return new Set([...fromAllowedList, ...fromGroups].filter(Boolean))
}

function filterCatalogByWhitelist(catalog: Catalog, whitelist: AllowedPnRuntime): Catalog {
  const allowed = getAllowedPnSet(whitelist)

  const filterGroups = (groups: CatalogGroup[]): CatalogGroup[] => {
    return groups
      .map((group) => ({
        ...group,
        partNumbers: group.partNumbers.filter((pn) => allowed.has(normalizePn(pn.partNumber))),
      }))
      .filter((group) => group.partNumbers.length > 0)
  }

  return {
    ...catalog,
    chassis: filterGroups(catalog.chassis || []),
    controllers: filterGroups(catalog.controllers || []),
    modules: filterGroups(catalog.modules || []),
  }
}

function enrichCatalogModels(catalog: Catalog): Catalog {
  const lookup = pnToModel as Record<string, string>
  const controllerSpecLookup = embeddedControllerSpecs as Record<string, {
    processor?: string
    frequency?: string
    numberOfCores?: number
    priceUsd?: number | null
    priceLabel?: string
  }>
  const productDescriptionLookup = Object.fromEntries(
    (niProductDescriptions as Array<{
      partNumber: string
      shortDescription?: string
      longDescription?: string
      error?: string
    }>)
      .filter((item) => item.partNumber && !item.error)
      .map((item) => [item.partNumber.trim(), item]),
  ) as Record<string, { shortDescription?: string; longDescription?: string }>
  const productImageLookup = Object.fromEntries(
    (niProductImages as Array<{
      partNumber: string
      imageUrl?: string | null
    }>)
      .filter((item) => item.partNumber)
      .map((item) => [item.partNumber.trim(), item.imageUrl || null]),
  ) as Record<string, string | null>
  const enrichGroups = (groups: CatalogGroup[]): CatalogGroup[] =>
    groups.map((group) => ({
      ...group,
      partNumbers: group.partNumbers.map((part) => {
        const csvModel = lookup[part.partNumber?.trim()]
        const controllerSpec = part.category === 'controller' ? controllerSpecLookup[part.partNumber?.trim()] : undefined
        const productDescriptions = productDescriptionLookup[part.partNumber?.trim()]
        const productImage = productImageLookup[part.partNumber?.trim()]

        return {
          ...part,
          ...(csvModel ? { model: csvModel } : {}),
          ...(productDescriptions?.shortDescription ? { description: productDescriptions.shortDescription } : {}),
          ...(productDescriptions?.longDescription ? { longDescription: productDescriptions.longDescription } : {}),
          productImage: productImage || '/no-image-available.svg',
          ...(controllerSpec?.processor ? { processor: controllerSpec.processor } : {}),
          ...(controllerSpec?.frequency ? { frequency: controllerSpec.frequency } : {}),
          ...(Number.isFinite(controllerSpec?.numberOfCores) ? { numberOfCores: controllerSpec?.numberOfCores } : {}),
          ...(controllerSpec?.priceLabel ? { priceLabel: controllerSpec.priceLabel } : {}),
          ...(typeof controllerSpec?.priceUsd === 'number' ? { price: controllerSpec.priceUsd } : {}),
        }
      }),
    }))

  return {
    ...catalog,
    chassis: enrichGroups(catalog.chassis || []),
    controllers: enrichGroups(catalog.controllers || []),
    modules: enrichGroups(catalog.modules || []),
  }
}

export async function loadAllowedPnsRuntime(): Promise<AllowedPnRuntime> {
  if (whitelistCache) return whitelistCache
  whitelistCache = rawWhitelist as AllowedPnRuntime
  return whitelistCache
}

export async function loadBusinessRules(): Promise<BusinessRules> {
  if (businessRulesCache) return businessRulesCache
  businessRulesCache = rawBusinessRules as BusinessRules
  return businessRulesCache
}

export async function loadCatalog(): Promise<Catalog> {
  if (catalogCache) return catalogCache

  const [whitelist] = await Promise.all([loadAllowedPnsRuntime()])
  const catalog = rawCatalog as Catalog
  const enriched = enrichCatalogModels(catalog)
  catalogCache = filterCatalogByWhitelist(enriched, whitelist)
  return catalogCache
}

export function clearCache(): void {
  catalogCache = null
  whitelistCache = null
  businessRulesCache = null
}
